try {
  // Plano B: Extrai o JSON enviado via urlenconded ou raw text
  const rawBody = $input.first().json.payload || $input.first().json.body;
  const data = typeof rawBody === 'string' ? JSON.parse(rawBody) : rawBody;
  return data;
} catch (e) {
  return { error: "Dados inválidos ou payload ausente" };
}

